/* ═══════════════════════════════════════════════
   CIRUGÍA ORTOPÉDICA Y TRAUMATOLOGÍA
   ARCHIVO 1 DE 3 — Preguntas 1-100
   Temas: Fracturas (generalidades, consolidación,
          complicaciones, miembro superior)
   Basado en: Manual   Traumatología y Cirugía
              Ortopédica, 10.ª edición

   DIFICULTAD: easy | medium | hard
   RESPUESTA:  0=A  1=B  2=C  3=D
═══════════════════════════════════════════════ */
var ENURM_CIRUGIA1 = [
  {id:'cir1_1',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cómo se define una fractura?',opts:['Interrupción de la continuidad ósea y/o cartilaginosa','Lesión ligamentosa con inestabilidad articular','Contusión ósea sin pérdida de continuidad','Deformidad plástica del hueso sin trazo de fractura'],ans:0,exp:'<b>Corre :</b> Una fractura se define como la interrupción de la continuidad ósea y/o cartilaginosa, habitualmente producida como consecuencia de un traumatismo único de intensidad superior a la que el hueso sano puede soportar. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_2',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la causa subyacente más frecuente en las fracturas patológicas?',opts:['Metástasis óseas','Osteomielitis crónica','Osteoporosis','Enfermedad de Paget'],ans:2,exp:'<b>Corre :</b> La osteoporosis es actualmente la causa subyacente más frecuente en las fracturas patológicas, especialmente en mujeres postmenopáusicas con osteoporosis no diagnosticada o no tratada. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_3',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la fractura por fatiga (estrés) más conocida y frecuente?',opts:['Fractura del escafoides carpiano','Fractura del recluta o de Deutschlander del 2.º metatarsiano','Fractura de Jones del 5.º metatarsiano','Fractura de cuello femoral'],ans:1,exp:'<b>Corre :</b> La fractura del recluta o de Deutschlander de la diáfisis del segundo metatarsiano es la fractura por estrés más conocida y frecuente. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_4',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuándo suele ser visible el callo óseo radiológicamente en las fracturas por fatiga?',opts:['A los 2-4 días','A las 2-3 semanas','A las 6-8 semanas','A los 3 meses'],ans:2,exp:'<b>Corre :</b> El callo óseo es habitualmente visible hacia las 6-8 semanas desde el inicio del dolor en las fracturas por fatiga. En la fase inicial no se aprecia en la radiografía. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_5',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué tipo de consolidación de fractura ocurre cuando se consigue reducción anatómica y ausencia prácticamente completa de movimiento?',opts:['Consolidación secundaria (indirecta)','Consolidación directa, cortical o primaria','Consolidación por callo blando','Consolidación endocondral'],ans:1,exp:'<b>Corre :</b> La consolidación directa, cortical o primaria (per primam) únicamente se produce cuando se consigue una reducción anatómica de los fragmentos y una ausencia prácticamente completa de movimiento, como ocurre con osteosíntesis con placas y tornillos. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_6',type:'mc',diff:'medium',sub:'cirugia',text:'¿En qué fase de la consolidación indirecta se forma tejido cartilaginoso (callo blando) por hipoxia?',opts:['Fase 1: impa  y formación de hematoma','Fase 2: formación del callo de fractura','Fase 3: osificación del callo','Fase 4: remodelación'],ans:1,exp:'<b>Corre :</b> En la fase 2 (formación del callo de fractura), la hipoxia de la zona central determina la formación de callo blando con colágeno tipo II y condroblastos. En la zona periférica (alta tensión de O2) se forma callo duro por osificación endomembranosa. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_7',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué tipo de hueso se forma exclusivamente en el feto y en el callo de fractura?',opts:['Hueso laminar maduro','Hueso cortical denso','Hueso fibrilar (woven bone)','Hueso esponjoso trabecular'],ans:2,exp:'<b>Corre :</b> El hueso fibrilar (woven bone) sólo se encuentra en el feto y en el callo de fractura. Se caracteriza por una orientación trabecular irregular y va siendo progresivamente transformado en hueso maduro mediante remodelación. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_8',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué proteínas morfogenéticas óseas están más implicadas en el proceso de consolidación?',opts:['BMP-1 y BMP-3','BMP-2 y BMP-7 (OP-1)','IGF-1 y IGF-2','TGF-β y PDGF'],ans:1,exp:'<b>Corre :</b> Las proteínas óseas morfogenéticas más implicadas en el proceso de consolidación son la BMP-2 y la BMP-7 (proteína osteogénica 1 [OP-1]). Regulan la diferenciación celular en sentido osteoblástico. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_9',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cómo se denomina un material que posee tanto las células como los fa res de crecimiento necesarios para la formación autónoma de hueso?',opts:['Osteocondu r','Osteoindu r','Osteogénico','Osteointegrador'],ans:2,exp:'<b>Corre :</b> Un material osteogénico (como la cresta ilíaca) posee tanto las células como los fa res de crecimiento necesarios para la formación autónoma de hueso. La osteoinducción estimula células propias del receptor; la osteoconductividad facilita la invasión ósea. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_10',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuándo se habla de retraso de consolidación?',opts:['Cuando la fractura consolida pasados más de 3 meses','Cuando la fractura consolida pasados más de 6 meses','Cuando a los 6 meses no hay signos de consolidación','Cuando a los 12 meses persiste el foco de fractura visible'],ans:0,exp:'<b>Corre :</b> Se habla de retardo o retraso de consolidación cuando una fractura consolida pasado más tiempo del habitual para el hueso del que se trate (aproximadamente 3 meses). La ausencia de consolidación se emplea cuando se anticipa que no consolidará (unos 6 meses). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_11',type:'mc',diff:'medium',sub:'cirugia',text:'En la ausencia de consolidación hipertrófica los extremos óseos están ensanchados con imagen de "pata de elefante". ¿A qué se debe fundamentalmente?',opts:['Mala vascularización','Infección del foco','Excesiva movilidad por falta de estabilidad','Interposición de partes blandas'],ans:2,exp:'<b>Corre :</b> La ausencia de consolidación hipertrófica se debe fundamentalmente a la excesiva movilidad del foco de la fractura por falta de estabilidad (inmovilización incorrecta). La atrófica se debe a mala vascularización. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_12',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué se entiende por pseudoartrosis?',opts:['Fractura que no consolida antes de 3 meses','Ausencia de consolidación con formación de cavidad con membrana pseudosinovial y líquido','Fractura consolidada en mala posición angular','Fractura que consolida por hueso fibrilar en exceso'],ans:1,exp:'<b>Corre :</b> Se denomina pseudoartrosis a la ausencia de consolidación en la que se forma una cavidad con una membrana pseudosinovial y líquido en su interior. Suele tratarse de ausencias de consolidación de larga evolución. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_13',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la indicación primaria del diagnóstico por TC en las fracturas?',opts:['Fracturas de huesos largos','Fracturas de húmero proximal, pelvis, acetábulo, calcáneo y vértebras','Fracturas de escafoides carpiano','Fracturas del radio distal en el adulto mayor'],ans:1,exp:'<b>Corre :</b> En determinadas fracturas (húmero proximal, pelvis, acetábulo, calcáneo, vertebrales) puede estar indicada la TC para un mejor diagnóstico y planificación del tratamiento. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_14',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuáles son los tres grados de la clasificación de las fracturas abiertas de Gustilo?',opts:['Leve, moderada y grave','I, II y III (con subtipos IIIA, IIIB y IIIC)','A, B y C','1, 2 y 3 (sin subtipos)'],ans:1,exp:'<b>Corre :</b> La clasificación de Gustilo para fracturas abiertas distingue los grados I, II y III, siendo el grado III el más grave y subdividiéndose en IIIA, IIIB y IIIC según el grado de contaminación, destrucción de partes blandas y lesión vascular. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_15',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la triada clínica del síndrome de embolia grasa?',opts:['Dolor, fiebre y petequias','Alteración del nivel de consciencia (intervalo lúcido ~24-36 h), sintomatología respiratoria y petequias en tórax, axila y conjuntiva','Dolor torácico, hemoptisis e hipotensión','Fiebre, anemia y trombocitopenia aisladas'],ans:1,exp:'<b>Corre :</b> La triada del síndrome de embolia grasa es: 1) sintomatología respiratoria (SDRA), 2) sintomatología neurológica cambiante con intervalo lúcido de 24-36 h, y 3) petequias en tórax, axila, raíz del cuello y conjuntiva. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_16',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el parámetro analítico de mayor valor en el síndrome de embolia grasa?',opts:['Trombocitopenia aislada','Elevación de PCR','Hipoxemia (PO2 < 60 mmHg)','Anemia ferropénica'],ans:2,exp:'<b>Corre :</b> El parámetro analítico de mayor valor en el síndrome de embolia grasa es la hipoxemia (generalmente PO2 < 60 mmHg), habitualmente acompañada de anemia y trombocitopenia. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_17',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el hallazgo típico en la radiografía de tórax del síndrome de embolia grasa?',opts:['Derrame pleural bilateral','Imagen en "tormenta de nieve" progresiva','Consolidación lobar única','Neumotórax bilateral'],ans:1,exp:'<b>Corre :</b> La radiografía de tórax presenta característicamente una imagen en "tormenta de nieve" progresiva en el síndrome de embolia grasa. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_18',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la principal medida profiláctica del síndrome de embolia grasa?',opts:['Administrar corticoides profilácticos','Realizar la correcta y precoz fijación de las fracturas','Iniciar anticoagulación sistemática','Administrar oxígeno hiperbárico'],ans:1,exp:'<b>Corre :</b> Lo principal en la profilaxis del síndrome de embolia grasa es la correcta y precoz fijación de la fractura (en la mayoría de los casos un enclavado de fémur). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_19',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento del síndrome de embolia grasa?',opts:['Antibioterapia empírica + fisioterapia respiratoria','Oxigenoterapia ± ventilación mecánica + corticoides IV en dosis altas + estabilización precoz de las fracturas','Anticoagulación con heparina + reposo absoluto','Drenaje pleural bilateral + soporte nutricional'],ans:1,exp:'<b>Corre :</b> El tratamiento del síndrome de embolia grasa incluye: oxigenoterapia (con o sin VM), corticoides en dosis altas IV (30 mg/kg de metilprednisolona en 2 dosis separadas 4 h) y estabilización precoz de las fracturas. Debe realizarse en UCI. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_20',type:'mc',diff:'medium',sub:'cirugia',text:'En el síndrome compartimental, ¿cuál es el síntoma más precoz y característico?',opts:['Paresia progresiva','Palidez de la extremidad','Dolor desproporcionado al traumatismo','Pulso periférico ausente'],ans:2,exp:'<b>Corre :</b> El dolor desproporcionado al traumatismo es el síntoma más precoz y característico del síndrome compartimental. La paresia, palidez y pulso ausente son signos tardíos. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_21',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el tratamiento definitivo del síndrome compartimental establecido?',opts:['Elevación del miembro y apertura del vendaje','Fasciotomía','Antiinflamatorios sistémicos y frío local','Anticoagulación y reposo'],ans:1,exp:'<b>Corre :</b> El tratamiento del síndrome compartimental establecido es la fasciotomía. Como medida inicial se realiza apertura del vendaje y elevación, pero si no resuelve, la fasciotomía es imprescindible. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_22',type:'mc',diff:'easy',sub:'cirugia',text:'¿En qué localizaciones se produce más frecuentemente el síndrome compartimental?',opts:['Muslo y glúteo','Tibia, antebrazo y codo','Pelvis y cadera','Pie y tobillo'],ans:1,exp:'<b>Corre :</b> El síndrome compartimental se localiza principalmente en la tibia, el antebrazo y el codo. La tibia es la localización más frecuente. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_23',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la secuela más grave del síndrome compartimental del antebrazo?',opts:['Necrosis de la piel','Contractura isquémica de Volkmann','Infección profunda','Artrosis postraumática'],ans:1,exp:'<b>Corre :</b> La contractura isquémica de Volkmann es la secuela más grave del síndrome compartimental del antebrazo. Se produce por fibrosis de los músculos necrosados, con retracciones importantes y malposiciones articulares. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_24',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuáles son las características del SDRC (síndrome de dolor regional complejo)?',opts:['Dolor en territorio de un nervio periférico que cede con reposo','Dolor quemante que no corresponde a ningún dermatoma, con hiperestesia y tendencia a progresar proximalmente','Dolor pulsátil con edema y eritema localizado','Dolor nocturno con limitación de la movilidad pasiva'],ans:1,exp:'<b>Corre :</b> El SDRC se caracteriza por dolor quemante que no corresponde al territorio de ningún dermatoma o nervio periférico, tiende a progresar proximalmente y se acompaña de hiperestesia (el paciente protege el miembro afectado). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_25',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el tratamiento de elección para la fractura de clavícula en la gran mayoría de los casos?',opts:['Cirugía con placa y tornillos siempre','Tratamiento conservador con vendaje en 8','Tratamiento conservador con yeso torácico','Enclavado intramedular'],ans:1,exp:'<b>Corre :</b> La inmensa mayoría de las fracturas de clavícula se tratan de forma conservadora, con un vendaje en 8 (si muy desplazada) o un vendaje de Velpeau (si poco desplazada), durante 4-5 semanas en el adulto. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_26',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la técnica de elección cuando el tratamiento quirúrgico está indicado en la fractura de clavícula?',opts:['Enclavado intramedular flexible','Fijador externo','Osteosíntesis con placa y tornillos','Agujas de Kirschner percutáneas'],ans:2,exp:'<b>Corre :</b> La técnica de elección en el tratamiento quirúrgico de la fractura de clavícula es la osteosíntesis con placa y tornillos. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_27',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la complicación más frecuente de la fractura de clavícula?',opts:['Necrosis avascular','Síndrome de embolia grasa','Consolidación en mala posición (con repercusión principalmente estética)','Pseudoartrosis con inestabilidad crónica'],ans:2,exp:'<b>Corre :</b> La principal complicación de la fractura de clavícula es la consolidación en mala posición, cuyas repercusiones son casi exclusivamente de tipo estético, aunque en ocasiones puede ocasionar compresión del plexo braquial. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_28',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuántos segmentos principales distingue la clasificación de Neer en el húmero proximal?',opts:['Dos: diáfisis y cabeza','Tres: cabeza, troquíter y troquín','Cuatro: diáfisis, cabeza, troquíter y troquín','Cinco: incluyendo también el cuello anatómico'],ans:2,exp:'<b>Corre :</b> La clasificación de Neer distingue cuatro segmentos principales en el húmero proximal: la diáfisis, la cabeza, el troquíter y el troquín. La fractura en cuatro partes aísla los cuatro fragmentos. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_29',type:'mc',diff:'medium',sub:'cirugia',text:'¿En qué tipo de fracturas de húmero proximal existe mayor riesgo de necrosis cefálica?',opts:['Fracturas no desplazadas','Fracturas en dos fragmentos del cuello quirúrgico','Fracturas en cuatro partes o del cuello anatómico (especialmente si hay luxación asociada)','Fracturas del troquíter aislado'],ans:2,exp:'<b>Corre :</b> Cuando el trazo de fractura aísla la cabeza humeral del resto de segmentos (como en las fracturas en cuatro partes o las del cuello anatómico), existe mayor riesgo de necrosis cefálica o ausencia de consolidación, especialmente si hay luxación asociada. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_30',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cómo se llama el hematoma característico de las fracturas de húmero proximal que ocupa la cara medial del brazo y lateral del tórax?',opts:['Hematoma de Hennequin','Equimosis de Hennequin','Signo de Malgaigne','Signo de Battle'],ans:1,exp:'<b>Corre :</b> A las 48 h de la fractura de húmero proximal suele haberse establecido la equimosis de Hennequin, que ocupa la cara medial del brazo y lateral del tórax. No requiere ninguna medida específica. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_31',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la principal complicación de las fracturas de húmero proximal?',opts:['Síndrome compartimental','Pseudoartrosis','Limitación de la movilidad del hombro','Necrosis avascular de la cabeza humeral'],ans:2,exp:'<b>Corre :</b> La principal complicación de las fracturas de húmero proximal es la limitación de la movilidad del hombro (rigidez). La necrosis avascular es también una complicación, pero menos frecuente. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_32',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el nervio más frecuentemente lesionado en las fracturas de la diáfisis humeral?',opts:['Nervio cubital','Nervio radial','Nervio mediano','Nervio musculocutáneo'],ans:1,exp:'<b>Corre :</b> El nervio más frecuentemente lesionado en las fracturas de la diáfisis humeral es el nervio radial (especialmente en el tercio medio-distal), produciendo parálisis de la extensión de la muñeca y dedos ("mano en gota"). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_33',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la fractura más frecuente del radio distal?',opts:['Fractura de Barton','Fractura de Smith (en extensión)','Fractura de Colles (en extensión dorsal)','Fractura-luxación de Galleazzi'],ans:2,exp:'<b>Corre :</b> La fractura de Colles es la fractura más frecuente del radio distal. Se produce por caída sobre la mano extendida con desplazamiento dorsal del fragmento distal (deformidad en "dorso de tenedor"). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_34',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué fractura del radio distal tiene el fragmento distal desplazado volarmente?',opts:['Fractura de Colles','Fractura de Barton','Fractura de Smith','Fractura de Chauffeur'],ans:2,exp:'<b>Corre :</b> La fractura de Smith ("fractura de Colles invertida") se produce por caída sobre el dorso de la mano con desplazamiento volar (palmar) del fragmento distal. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_35',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué asociación caracteriza la fractura de Monteggia?',opts:['Fractura de radio distal + luxación de la articulación radiocubital distal','Fractura de cúbito proximal + luxación de la cabeza radial','Fractura de diáfisis radial + luxación de cúbito distal','Fractura supracondílea + lesión del nervio mediano'],ans:1,exp:'<b>Corre :</b> La fractura de Monteggia consiste en la fractura de la diáfisis del cúbito proximal asociada a luxación de la cabeza radial. La fractura de Galleazzi combina fractura de radio distal con luxación de la articulación radiocubital distal. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_36',type:'mc',diff:'hard',sub:'cirugia',text:'¿Por qué el escafoides carpiano tiene tendencia a la necrosis avascular y a la ausencia de consolidación?',opts:['Por su localización subcutánea','Por su vascularización precaria (el flujo entra por el polo distal)','Por la constante movilización de la muñeca','Por la elevada presión que soporta durante la prensión'],ans:1,exp:'<b>Corre :</b> El escafoides carpiano tiene una vascularización precaria (la sangre entra principalmente por el polo distal), de modo que las fracturas del tercio proximal tienen mayor riesgo de necrosis avascular y ausencia de consolidación. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_37',type:'mc',diff:'easy',sub:'cirugia',text:'¿Con qué maniobra se diagnóstica la fractura de escafoides en la exploración?',opts:['Maniobra de Finkelstein','Dolor a la palpación en la tabaquera anatómica','Test de Watson','Signo de Tinel en la muñeca'],ans:1,exp:'<b>Corre :</b> El dolor a la palpación en la tabaquera anatómica (fosa entre el tendón extensor largo del pulgar y el abdu r largo + extensor corto del pulgar) es el signo clínico más característico de la fractura de escafoides. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_38',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la fractura más frecuente de toda la economía ósea en los adultos mayores?',opts:['Fractura de radio distal','Fractura de cuello de fémur','Fractura de vértebra lumbar','Fractura de húmero proximal'],ans:1,exp:'<b>Corre :</b> La fractura de cuello de fémur es la fractura más frecuente en adultos mayores y una de las más importantes por su morbimortalidad. Las de radio distal son frecuentes, pero las de cadera tienen mayor impa  pronóstico. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_39',type:'mc',diff:'medium',sub:'cirugia',text:'¿Por qué la fractura del cuello anatómico del fémur tiene mayor riesgo de necrosis avascular que la del cuello quirúrgico?',opts:['Porque produce mayor sangrado','Porque lesiona los vasos retinaculares que irrigan la cabeza femoral','Porque es más difícil de reducir','Porque afecta al cartílago articular directamente'],ans:1,exp:'<b>Corre :</b> Las fracturas del cuello anatómico del fémur dañan los vasos retinaculares que discurren por la cápsula articular y son los principales responsables de la irrigación de la cabeza femoral, aumentando el riesgo de necrosis avascular. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_40',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la clasificación más utilizada para las fracturas del extremo proximal del fémur (cuello femoral)?',opts:['Clasificación AO','Clasificación de Garden','Clasificación de Pauwels','Clasificación de Neer'],ans:1,exp:'<b>Corre :</b> La clasificación de Garden es la más utilizada para las fracturas del cuello femoral. Distingue 4 grados: I (incompleta en valgo), II (completa no desplazada), III (desplazada parcialmente), IV (completamente desplazada). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_41',type:'mc',diff:'medium',sub:'cirugia',text:'En una fractura subcapital de fémur desplazada (Garden III-IV) en un paciente de 80 años, ¿cuál es el tratamiento más adecuado?',opts:['Reducción cerrada y yeso pelvipédico','Reducción abierta y osteosíntesis con tornillos canulados','Artroplastia (prótesis parcial o total)','Tracción esquelética durante 6 semanas'],ans:2,exp:'<b>Corre :</b> En el paciente anciano con fractura subcapital desplazada (Garden III-IV), el tratamiento de elección es la artroplastia (prótesis parcial de cadera o total según el estado biológico), para permitir la carga precoz y evitar el prolongado encamamiento. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_42',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la diferencia principal entre las fracturas pertrocantéreas y las del cuello femoral?',opts:['Las pertrocantéreas tienen mayor riesgo de necrosis avascular','Las pertrocantéreas son extracapsulares y tienen mejor vascularización, por lo que consolidan mejor','Las pertrocantéreas afectan a la superficie articular','Las pertrocantéreas son más frecuentes en pacientes jóvenes'],ans:1,exp:'<b>Corre :</b> Las fracturas pertrocantéreas son extracapsulares, tienen mejor vascularización (zona esponjosa bien vascularizada), menor riesgo de necrosis avascular y consolidan mejor que las fracturas del cuello femoral (intracapsulares). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_43',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento de elección para la fractura pertrocantérea de fémur?',opts:['Tratamiento conservador con tracción esquelética','Tornillos canulados percutáneos','Clavo intramedular cefalomedullar (tipo PFN o GAMMA)','Prótesis de cadera de urgencia'],ans:2,exp:'<b>Corre :</b> El tratamiento de elección para la fractura pertrocantérea de fémur es el clavo intramedular cefalomedullar (tipo clavo gamma o PFN), que permite la carga precoz. La osteosíntesis con placa-tornillo deslizante (DHS) también es válida en fracturas estables. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_44',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el tratamiento de elección de la fractura diafisaria de fémur en el adulto?',opts:['Yeso pelvipédico','Tracción esquelética continua','Enclavado intramedular bloqueado','Osteosíntesis con placa y tornillos'],ans:2,exp:'<b>Corre :</b> El enclavado intramedular bloqueado (clavo endomedular) es el tratamiento de elección para la fractura diafisaria de fémur en el adulto, por su baja morbilidad, alta tasa de consolidación y posibilidad de carga precoz. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_45',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la complicación más temida a corto plazo de las fracturas de diáfisis femoral?',opts:['Pseudoartrosis','Síndrome compartimental del muslo','Embolia grasa','Lesión de la arteria femoral profunda'],ans:2,exp:'<b>Corre :</b> La embolia grasa es la complicación más temida a corto plazo de las fracturas de diáfisis femoral, especialmente cuando se demora su fijación quirúrgica. El sangrado abundante (hasta 2 l) también es relevante. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_46',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cómo se tratan las fracturas supracondíleas de fémur?',opts:['Yeso cruropédico en extensión','Clavo intramedular anterógrado','Placa y tornillos o clavo intramedular retrógrado','Tracción transesquelética durante 6-8 semanas'],ans:2,exp:'<b>Corre :</b> Las fracturas supracondíleas de fémur se tratan con placa y tornillos o clavo intramedular retrógrado. No es infrecuente que ocurran en pacientes con artroplastia de rodilla previa (fracturas periprotésicas). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_47',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué mecanismo traumático produce típicamente las fracturas de la meseta tibial lateral?',opts:['Compresión axial','Valgo forzado (traumatismo en cara lateral de la rodilla)','Varo forzado','Hiperflexión de la rodilla'],ans:1,exp:'<b>Corre :</b> Las fracturas de la meseta tibial lateral suelen producirse por valgo forzado (típicamente un traumatismo sobre la cara lateral de la rodilla, como el parachoques de un vehículo en un atropello). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_48',type:'mc',diff:'medium',sub:'cirugia',text:'¿Con qué lesión nerviosa puede asociarse la fractura de meseta tibial medial?',opts:['Lesión del nervio tibial posterior','Lesión del nervio safeno','Lesión del nervio peroneo por elongación','Lesión del nervio femoral'],ans:2,exp:'<b>Corre :</b> Las fracturas de la meseta tibial medial se producen por varo forzado, son de mayor energía y pueden asociarse a lesión del nervio peroneo por elongación del mismo en el momento del traumatismo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_49',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la fractura de rótula que requiere osteosíntesis?',opts:['Fractura por avulsión pequeña del polo inferior','Fractura transversa que interrumpe el aparato extensor','Fractura estrellada sin desplazamiento','Fractura conminuta sin desplazamiento'],ans:1,exp:'<b>Corre :</b> Las fracturas transversas de rótula interrumpen totalmente el aparato extensor y el cuádriceps mantiene los fragmentos desplazados, por lo que requieren osteosíntesis (generalmente dos agujas y un cerclaje). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_50',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el tratamiento de elección para las fracturas desplazadas de diáfisis tibial?',opts:['Yeso inguinopédico con carga inmediata','Osteosíntesis con placa posterior','Enclavado intramedular','Fijador externo en todos los casos'],ans:2,exp:'<b>Corre :</b> El tratamiento quirúrgico de elección en las fracturas desplazadas de diáfisis tibial es el enclavado intramedular. Las fracturas abiertas grados IIIB y IIIC suelen estabilizarse inicialmente con fijador externo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_51',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la causa más frecuente de síndrome compartimental?',opts:['Fractura de húmero','Fractura de fémur','Fractura de tibia','Fractura de radio distal'],ans:2,exp:'<b>Corre :</b> Las fracturas de tibia son actualmente la causa más frecuente de síndrome compartimental, y también la localización más frecuente de fracturas abiertas. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_52',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué es la fractura de Maisonneuve?',opts:['Fractura bimaleolar con luxación lateral del tobillo','Fractura del tercio proximal del peroné asociada a lesión del ligamento deltoideo','Fractura de pilón tibial con afectación del tobillo','Fractura transversa del maléolo lateral con hematoma'],ans:1,exp:'<b>Corre :</b> La fractura de Maisonneuve es la fractura del tercio proximal del peroné asociada a lesión del ligamento deltoideo (complejo medial). Es suprasindesmal y siempre hay lesión del complejo medial. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_53',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cómo se llama la fractura-luxación de tobillo que combina fractura bimaleolar con luxación lateral?',opts:['Fractura de Pilon','Fractura de Maisonneuve','Fractura de Dupuytren','Fractura de Pott'],ans:2,exp:'<b>Corre :</b> La fractura de Dupuytren es la fractura bimaleolar (suprasindesmal) que frecuentemente se presenta con el tobillo luxado lateralmente. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_54',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el signo radiológico de buen pronóstico en las fracturas de cuello del astrágalo?',opts:['Signo de la doble línea en RM','Signo de Hawkins (resorción subcondral del cuerpo astragalino)','Línea de hiposeñal en T1','Halo de hipercaptación en gammagrafía'],ans:1,exp:'<b>Corre :</b> El signo de Hawkins (resorción subcondral del cuerpo del astrágalo) ocurre en las fracturas en las que se mantiene una buena vascularización, por lo que es un signo radiológico de buen pronóstico. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_55',type:'mc',diff:'medium',sub:'cirugia',text:'¿Con qué otras fracturas se asocia frecuentemente la fractura de calcáneo por caída desde altura?',opts:['Fractura de escafoides y pelvis','Fractura de meseta tibial y vértebra lumbar','Fractura de húmero proximal y costillas','Fractura de astrágalo y peroné'],ans:1,exp:'<b>Corre :</b> Las fracturas de calcáneo se producen por caídas desde altura con traumatismo axial, por lo que se pueden asociar con fracturas de meseta tibial y vértebras lumbares. Las más frecuentemente asociadas a caídas desde altura son, en orden: calcáneo, meseta tibial y vértebra lumbar. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_56',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué fractura del quinto metatarsiano tiene mayor incidencia de ausencia de consolidación?',opts:['Avulsión de la apófisis estiloides','Fractura de Jones (unión metafisodiafisaria)','Fractura por fatiga de la diáfisis proximal','Fractura del cuello del quinto metatarsiano'],ans:1,exp:'<b>Corre :</b> Las fracturas de Jones (en la unión metafisodiafisaria del quinto metatarsiano) tienen una incidencia relativamente alta de ausencia de consolidación. En deportistas de élite se recomienda osteosíntesis con tornillo intramedular. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_57',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la indicación de las fracturas de pelvis estables?',opts:['Fijador externo de urgencia','Osteosíntesis definitiva inmediata','Tratamiento conservador','Tracción esquelética bilateral'],ans:2,exp:'<b>Corre :</b> Las fracturas de pelvis estables se tratan de forma conservadora. Las fracturas inestables requieren fijador externo como medida de urgencia para controlar el sangrado, seguido de osteosíntesis definitiva. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_58',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuándo está indicada la osteosíntesis en las fracturas de acetábulo?',opts:['Siempre','Cuando el desplazamiento es mayor de 2 mm o hay fragmento intraarticular','Solo en fracturas abiertas','Cuando se asocian a luxación de cadera'],ans:1,exp:'<b>Corre :</b> En las fracturas de acetábulo, la osteosíntesis está indicada cuando el desplazamiento es mayor de 2 mm o existe un fragmento intraarticular que comprometa la congruencia articular. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_59',type:'mc',diff:'medium',sub:'cirugia',text:'En los niños, ¿qué fracturas específicas se producen por la mayor flexibilidad del hueso?',opts:['Fracturas conminutas y fracturas abiertas','Fracturas en rodete, en tallo verde e incurvaciones plásticas','Fracturas por arrancamiento de apófisis','Fracturas por estrés de la diáfisis'],ans:1,exp:'<b>Corre :</b> El esqueleto en desarrollo es más flexible, lo que condiciona la existencia de fracturas específicas del niño: fracturas en rodete, en tallo verde e incurvaciones plásticas. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_60',type:'mc',diff:'medium',sub:'cirugia',text:'¿En qué tipo de epifisiólisis (Salter-Harris) el trazo provoca discontinuidad de la epífisis y asciende hacia la metáfisis desprendiendo un fragmento triangular?',opts:['Tipo I','Tipo II','Tipo III','Tipo IV'],ans:3,exp:'<b>Corre :</b> La epifisiólisis tipo IV de Salter-Harris tiene un trazo que provoca discontinuidad de la epífisis y asciende hacia la metáfisis desprendiendo un fragmento metafisario triangular. Es típica del cóndilo humeral lateral infantil. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_61',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el hueso más frecuentemente fracturado durante el parto?',opts:['Fémur','Húmero','Clavícula','Radio'],ans:2,exp:'<b>Corre :</b> La clavícula es el hueso más frecuentemente fracturado durante los partos distócicos. Se trata simplemente con inmovilización transitoria con la propia camiseta del niño. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_62',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la principal ventaja del enclavado intramedular frente a la osteosíntesis con placa en la diáfisis femoral?',opts:['Permite reducción anatómica perfecta','Es de menor coste económico','Es un implante a "carga compartida" que respeta mejor el periostio y la biología ósea','Requiere menos tiempo quirúrgico siempre'],ans:2,exp:'<b>Corre :</b> El enclavado intramedular es un implante de "carga compartida" que trabaja junto con el hueso, respeta mejor el periostio y la biología ósea (menos desperiostización), permitiendo tasas altas de consolidación y carga precoz. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_63',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la complicación más frecuente de las fracturas de tibia?',opts:['Síndrome compartimental','Ausencia de consolidación','Consolidación en mala posición','Infección del foco'],ans:1,exp:'<b>Corre :</b> Las principales complicaciones de las fracturas de tibia son la ausencia de consolidación y la consolidación en mala posición; sin embargo, el síndrome compartimental es la complicación más temida a corto plazo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_64',type:'mc',diff:'hard',sub:'cirugia',text:'¿Qué tensiones en el foco de fractura promueven la consolidación según los fa res biofísicos?',opts:['La compresión axial excesiva y el cizallamiento extremo','Las fuerzas de compresión axial moderada y los campos electromagnéticos','Solo los ultrasonidos de baja frecuencia','La distracción leve y los campos electromagnéticos exclusivamente'],ans:1,exp:'<b>Corre :</b> Las fuerzas de compresión axial moderada promueven la consolidación. También la favorecen los campos electromagnéticos y los ultrasonidos de baja intensidad. Un exceso de compresión induce cartílago; el exceso de distracción o cizallamiento, tejido fibroso. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_65',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento del síndrome compartimental agudo establecido?',opts:['Observación durante 24 h con elevación del miembro','Fasciotomía urgente de todos los compartimentos afectados','Anticoagulación sistémica + AINE','Hipotermia local y vendaje compresivo'],ans:1,exp:'<b>Corre :</b> El síndrome compartimental agudo establecido requiere fasciotomía urgente de todos los compartimentos afectados para aliviar la presión y preservar la función neurovascular. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_66',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué se denomina "fractura de Chauffeur" o del estiloides radial?',opts:['Fractura intraarticular del radio con desplazamiento dorsal','Fractura de la columna medial del radio con fragmento volar','Fractura por avulsión del estiloides radial','Fractura del radio distal con conminución dorsal'],ans:2,exp:'<b>Corre :</b> La fractura de Chauffeur (o del estiloides radial) es la fractura por avulsión del estiloides radial. Se producía antiguamente al girar la manivela de arranque del automóvil. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_67',type:'mc',diff:'hard',sub:'cirugia',text:'¿Qué fa r dificulta la consolidación de las fracturas según la tabla de fa res bioquímicos del  ?',opts:['Vitamina D','Insulina','Tratamiento con corticoides','Calcitonina'],ans:2,exp:'<b>Corre :</b> El tratamiento con corticoides (junto con la diabetes, déficit de hormona de crecimiento, malnutrición, indometacina/AINE, hipoxia, infección y tabaco) dificulta la consolidación de las fracturas. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_68',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la principal diferencia entre las fracturas de pilón tibial y las fracturas de tobillo comunes?',opts:['Las de pilón son siempre abiertas','Las de pilón afectan a la superficie articular distal de la tibia por impa  axial del astrágalo','Las de tobillo son más inestables','Las de pilón solo ocurren en jóvenes deportistas'],ans:1,exp:'<b>Corre :</b> Las fracturas de pilón tibial se producen en traumatismos axiales en los que el astrágalo impacta sobre la superficie distal de la tibia ("pilón"), produciendo una fractura habitualmente conminuta y desplazada. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_69',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué es la "fractura del aviador" y qué hueso afecta?',opts:['Fractura del astrágalo por hiperflexión dorsal','Fractura del calcáneo por impa  axial','Fractura de la rótula por golpe dire ','Fractura de pilón tibial por compresión axial'],ans:0,exp:'<b>Corre :</b> Las fracturas de astrágalo se denominan "fracturas del aviador" porque eran características de los antiguos aviadores que apretaban los pedales antes de un impa , rompiéndose sus astrágalos. Se producen por hiperflexión dorsal. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_70',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué tipo de fracturas de tobillo no requieren tratamiento quirúrgico?',opts:['Fracturas transindesmales desplazadas en pacientes jóvenes','Fracturas suprasindesmales con lesión del complejo medial','Fracturas infrasindesmales aisladas (avulsiones) o transindesmales/infrasindesmales en pacientes ancianos','Fracturas de pilón tibial conminutas'],ans:2,exp:'<b>Corre :</b> La edad avanzada es contraindicación relativa para la osteosíntesis del tobillo. Las fracturas infrasindesmales aisladas (avulsiones) y las trans o infrasindesmales en ancianos pueden tratarse con reducción cerrada e inmovilización con yeso. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_71',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuáles son las 3 complicaciones principales de las fracturas del cuello femoral?',opts:['Embolia grasa, infección y consolidación viciosa','Necrosis avascular de cabeza femoral, ausencia de consolidación y artrosis secundaria','Trombosis venosa, embolia pulmonar y síndrome compartimental','Lesión nerviosa, rigidez articular y consolidación en mala posición'],ans:1,exp:'<b>Corre :</b> Las tres complicaciones principales de las fracturas del cuello femoral son: 1) necrosis avascular de la cabeza femoral (la más temida), 2) ausencia de consolidación y 3) artrosis secundaria. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_72',type:'mc',diff:'easy',sub:'cirugia',text:'¿En qué tipo de fractura de tobillo existe lesión de la sindesmosis tibioperonea?',opts:['Infrasindesmal','Transindesmal','Suprasindesmal','Solo en la fractura de Pott'],ans:2,exp:'<b>Corre :</b> Las fracturas suprasindesmales prácticamente siempre se asocian a lesión del complejo medial y a menudo a lesión de la sindesmosis tibioperonea. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_73',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuáles son los requisitos de reducción aceptable para las fracturas de diáfisis tibial tratadas de forma conservadora?',opts:['Alineación perfecta sin acortamiento ni angulación','Menos de 1 cm de acortamiento, menos de 10º de angulación, buen alineamiento rotacional y conta  ≥50%','Menos de 5 mm de acortamiento y conta  ≥80%','Solo importa el alineamiento rotacional'],ans:1,exp:'<b>Corre :</b> Los criterios de reducción aceptable para las fracturas de tibia tratadas conservadoramente incluyen: <1 cm de acortamiento, <10º de angulación, buen alineamiento rotacional y conta  de al menos el 50%. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_74',type:'mc',diff:'hard',sub:'cirugia',text:'¿Cuál es la epifisiólisis de Salter-Harris tipo V?',opts:['Trazo que cursa en su totalidad por la tisis','Trazo que cursa por la tisis con fragmento metafisario triangular','Discontinuidad de la epífisis con trazo que prosigue a través de la tisis','Compresión axial con destrucción de las zonas de reserva y proliferativa'],ans:3,exp:'<b>Corre :</b> La epifisiólisis de Salter-Harris tipo V es una compresión axial con destrucción de las zonas de reserva y proliferativa del cartílago de crecimiento. Es la de peor pronóstico. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_75',type:'mc',diff:'medium',sub:'cirugia',text:'¿En qué caso puede diferirse la reducción de la luxación de cadera postraumática?',opts:['Nunca, siempre es una urgencia','Hasta 12 horas si el paciente está estable','La luxación de cadera es urgencia; si no se reduce antes de 6 horas, el riesgo de necrosis avascular aumenta marcadamente','Solo si hay fractura asociada del acetábulo'],ans:2,exp:'<b>Corre :</b> La luxación de cadera es una emergencia ortopédica. Si no se reduce de forma precoz (idealmente antes de 6 horas), el riesgo de necrosis avascular de la cabeza femoral aumenta marcadamente. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_76',type:'mc',diff:'easy',sub:'cirugia',text:'¿Por qué el escafoides tiene un diagnóstico radiológico inicial difícil?',opts:['Porque se superpone con el radio','Porque la fractura puede no verse en la radiografía inicial, siendo necesaria RMN o gammagrafía','Porque es un hueso muy pequeño y rara vez se fractura','Porque siempre requiere artro-TC'],ans:1,exp:'<b>Corre :</b> Las fracturas del escafoides carpiano pueden no apreciarse en la radiografía inicial. En esa fase puede ser de ayuda la gammagrafía (hipercaptación en el foco) o la RM (muestra cambios precoces). El callo óseo es visible hacia las 6-8 semanas. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_77',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cómo se denomina el tratamiento quirúrgico que consiste en inyectar un tornillo percutáneo en el foco de fractura del escafoides?',opts:['Osteosíntesis con aguja de Kirschner','Osteosíntesis con tornillo de Herbert','Placa de sostén volar','Artrodesis radiocarpiana'],ans:1,exp:'<b>Corre :</b> El tornillo de Herbert (sin cabeza) es el implante de elección para la osteosíntesis percutánea o abierta de la fractura del escafoides carpiano. Permite compresión entre los fragmentos. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_78',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué es la ley de Wolff en la remodelación ósea?',opts:['El hueso maduro siempre tiene mayor densidad que el fibrilar','La forma y estructura de los huesos dependen del estrés y la tensión a los que están sometidos','El calcio se deposita en mayor cantidad en los huesos de mayor longitud','Los osteoblastos actúan solo en respuesta a la hormona paratiroidea'],ans:1,exp:'<b>Corre :</b> La ley de Wolff establece que la forma y estructura de los huesos en crecimiento y de los adultos dependen del estrés y la tensión (esfuerzos/carga) a los que están sometidos. Explica la orientación trabecular en el hueso maduro. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_79',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el objetivo en la reducción de las fracturas articulares desplazadas?',opts:['Reducción mayor del 50% de la superficie','Reducción anatómica de la superficie articular para evitar artrosis postraumática','Solo estabilidad, no importa la reducción anatómica','Inmovilización prolongada sin reducción'],ans:1,exp:'<b>Corre :</b> En las fracturas articulares desplazadas, el objetivo es la reducción anatómica de la superficie articular (congruencia articular) para evitar el desarrollo de artrosis postraumática a largo plazo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_80',type:'mc',diff:'hard',sub:'cirugia',text:'¿Cuál es la diferencia entre fractura de Barton y fractura de Colles?',opts:['La Barton es extrarticular y la Colles intraarticular','La Barton es intraarticular con subluxación del carpo; la Colles es extrarticular del radio distal con deformidad en dorso de tenedor','Son sinónimos','La Colles es en niños y la Barton en adultos'],ans:1,exp:'<b>Corre :</b> La fractura de Barton es intraarticular del radio distal con subluxación del carpo (dorsal o volar). La fractura de Colles es extrarticular con desplazamiento dorsal del fragmento distal y no hay subluxación carpiana. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_81',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la primera opción de tratamiento en fracturas de húmero proximal en cuatro partes en pacientes biológicamente jóvenes?',opts:['Tratamiento conservador con Velpeau','Prótesis de sustitución como primera opción','Reducción y osteosíntesis como primera opción de tratamiento','Tracción esquelética'],ans:2,exp:'<b>Corre :</b> En pacientes biológicamente jóvenes con fracturas desplazadas de húmero proximal, independientemente del tipo de fractura, debería intentarse siempre una reducción y osteosíntesis como primera opción. La artroplastia se reserva para fracturas con destrucción articular o necrosis establecida. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_82',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué fa r bioquímico favorece la consolidación de las fracturas al regular la diferenciación celular en sentido osteoblástico?',opts:['IL-1 y IL-6','TGF-β y FGF (quimiotácticos)','BMP e IGF','PDGF exclusivamente'],ans:2,exp:'<b>Corre :</b> Las BMP (proteínas morfogenéticas óseas) y el IGF (fa r de crecimiento similar a la insulina) regulan la diferenciación celular en sentido osteoblástico, favoreciendo la consolidación. IL-1, IL-6, TGF-β, FGF y PDGF son principalmente quimiotácticos/mitogénicos. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_83',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuáles son las tres fases clásicas del SDRC?',opts:['Aguda, subaguda y crónica','Aguda (dolor y rubefacción), distrófica (edema y rigidez) y atrófica','Inflamatoria, proliferativa y de remodelación','Inicial, de progresión y de resolución'],ans:1,exp:'<b>Corre :</b> El SDRC clásicamente se divide en tres fases: 1) fase aguda (dolor, rubefacción, edema), 2) fase distrófica (edema, rigidez y amoratamiento) y 3) fase atrófica. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_84',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué imagen radiológica es característica de la osteoporosis en el SDRC?',opts:['Osteosclerosis difusa','Osteoporosis moteada que posteriormente se hace difusa','Reacción perióstica','Imagen lítica central'],ans:1,exp:'<b>Corre :</b> En el SDRC, la radiografía muestra osteoporosis moteada (signo de Sudeck) que posteriormente se hace difusa a medida que progresa el cuadro. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_85',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué tratamiento puede utilizarse para el SDRC además de fisioterapia y fármacos?',opts:['Heparina sistémica y vendaje compresivo','Bloqueos anestésicos y calcitonina (y en casos graves, simpate mía)','Cirugía de reducción y osteosíntesis inmediata','Hipotermia local durante 72 horas'],ans:1,exp:'<b>Corre :</b> El tratamiento del SDRC es multidisciplinar: fisioterapia, fármacos (AINE, calcitonina, psicofármacos), bloqueos anestésicos y en casos refractarios simpate mía. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_86',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuándo el SDRC puede aparecer incluso sin fractura?',opts:['Nunca, siempre requiere fractura previa','Sí, tanto el síndrome compartimental como el SDRC pueden aparecer sin fractura','Solo el SDRC puede aparecer sin fractura, no el síndrome compartimental','Solo en niños',''],ans:1,exp:'<b>Corre :</b> Tanto el síndrome compartimental como el SDRC pueden aparecer incluso sin fractura, como tras esguinces, quemaduras, intervenciones quirúrgicas o incluso de forma espontánea. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_87',type:'mc',diff:'hard',sub:'cirugia',text:'¿Cuál es la epifisiólisis de Salter-Harris más frecuente (tipo II) y su hallazgo radiológico característico?',opts:['Solo afecta la fisis; no hay fragmento óseo visible','Fragmento metafisario triangular (signo de Thurston-Holland) junto al trazo de fisis','Fractura intraepifisaria visible en radiografía como línea epifisaria','Imagen de compresión sin línea de fractura visible'],ans:1,exp:'<b>Corre :</b> La epifisiólisis de Salter-Harris tipo II es la más frecuente. El trazo cursa por la tisis y asciende hacia la metáfisis, desprendiendo un fragmento metafisario triangular (signo de Thurston-Holland). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_88',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué fractura supracondílea de húmero en el niño es la más frecuente y cuál es el nervio más frecuentemente lesionado?',opts:['Tipo en extensión; nervio radial','Tipo en extensión; nervio interóseo anterior (rama del mediano)','Tipo en flexión; nervio cubital','Tipo en extensión; nervio musculocutáneo'],ans:1,exp:'<b>Corre :</b> La fractura supracondílea en extensión es la más frecuente en el niño. El nervio interóseo anterior (rama del nervio mediano) es el más frecuentemente lesionado, aunque el nervio radial y el cubital también pueden verse afectados. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_89',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la arteria que puede lesionarse en la fractura supracondílea de húmero en el niño?',opts:['Arteria radial','Arteria cubital','Arteria humeral (braquial)','Arteria interósea anterior'],ans:2,exp:'<b>Corre :</b> La arteria humeral (braquial) es la que puede lesionarse en la fractura supracondílea de húmero en el niño, constituyendo una urgencia vascular y siendo causa potencial de síndrome compartimental y contractura de Volkmann. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_90',type:'mc',diff:'medium',sub:'cirugia',text:'¿En qué fractura del niño es característica la epifisiólisis tipo IV de Salter-Harris?',opts:['Epifisiólisis de cadera','Fractura del cóndilo humeral lateral','Fractura de la fisis distal del radio','Fractura de la fisis distal de la tibia'],ans:1,exp:'<b>Corre :</b> La epifisiólisis tipo IV de Salter-Harris es típica del cóndilo humeral lateral en el niño. El fragmento incluye epífisis y un fragmento metafisario triangular. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_91',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué es la tracción 90-90 y para qué se utiliza?',opts:['Tracción cervical en decúbito prono','Tracción de la extremidad superior a 90° de abducción','Tracción esquelética con el muslo vertical y la pierna horizontal, utilizada para fracturas de fémur en el niño','Tracción cutánea en decúbito supino a 90° de flexión de cadera'],ans:2,exp:'<b>Corre :</b> La tracción 90-90 (muslo vertical y pierna horizontal) es una técnica utilizada para las fracturas de fémur en el niño, especialmente en los primeros años de vida, aunque ha sido en gran parte desplazada por el enclavado elástico. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_92',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el índice de Pearl en traumatología que indica la calidad ósea de forma clínica?',opts:['Índice de Singh','Índice de Pauwels','Índice cortical','Índice de Garden'],ans:0,exp:'<b>Corre :</b> El índice de Singh es el que valora la calidad ósea (osteoporosis) en la cadera mediante la evaluación de los sistemas trabeculares del fémur proximal en la radiografía. Se divide en grados del 1 al 6. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_93',type:'mc',diff:'hard',sub:'cirugia',text:'¿Cuál es la epifisiólisis de Salter-Harris tipo III y en qué localización es frecuente?',opts:['Trazo solo por la fisis; frecuente en el radio distal','Trazo con fragmento metafisario; frecuente en el fémur distal','Trazo que provoca discontinuidad epifisaria y prosigue a través de la fisis; frecuente en la fisis tibial distal (fractura de Chaput-Tillaux)','Trazo de compresión pura; frecuente en la cadera'],ans:2,exp:'<b>Corre :</b> La epifisiólisis tipo III de Salter-Harris provoca discontinuidad de la epífisis y prosigue a través de la fisis. En la fisis tibial distal se denomina fractura de Chaput-Tillaux y es muy frecuente en ese nivel. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_94',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la principal ventaja de la consolidación en los niños frente a los adultos?',opts:['El periostio es más delgado y favorece la osificación perióstica','La elevada capacidad de remodelación permite aceptar deformidades que en el adulto serían intolerables, además de acortar el tiempo de consolidación','Los niños tienen más vascularización ósea','Los niños no desarrollan síndrome compartmental'],ans:1,exp:'<b>Corre :</b> La elevada capacidad de remodelación de los niños permite aceptar deformidades postraumáticas que en el adulto serían intolerables, acorta el tiempo de consolidación y hace prácticamente inexistente la ausencia de consolidación. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_95',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la fractura de la clavícula más frecuente y cómo se desplazan los fragmentos?',opts:['Fractura de tercio distal; el lateral cae por el peso del brazo','Fractura de tercio medio; el fragmento medial se desplaza posterosuperiormente por el ECM y el lateral anteroinferiormente por el peso de la extremidad','Fractura de tercio proximal; sin desplazamiento','Fractura de tercio distal con desplazamiento superior'],ans:1,exp:'<b>Corre :</b> La mayoría de las fracturas de clavícula se localizan en el tercio medio. El fragmento medial se desplaza posterosuperiormente por la acción del esternocleidomastoideo (ECM), y el lateral se sitúa anteroinferiormente por el peso de la extremidad superior. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_96',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento de la fractura de diáfisis tibial en fracturas abiertas grados IIIB y IIIC?',opts:['Enclavado intramedular inmediato','Osteosíntesis con placa anteromedial','Fijador externo inicial hasta que mejore el estado de partes blandas','Yeso inguinopédico con carga inmediata'],ans:2,exp:'<b>Corre :</b> Las fracturas abiertas de tibia grados IIIB y IIIC suelen estabilizarse con fijador externo inicialmente, dado el compromiso de partes blandas. No se recomienda placa ni enclavado inmediato en estos casos por riesgo de infección. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_97',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la complicación de las fracturas de calcáneo que puede producirse de forma tardía?',opts:['Embolia grasa','Síndrome compartmental del pie','Artrosis postraumática subastragalina con dolor crónico en el retropié','Necrosis avascular del astrágalo'],ans:2,exp:'<b>Corre :</b> Las fracturas talámicas intraarticulares del calcáneo pueden ocasionar, una vez consolidadas, dolor crónico en el retropié por artrosis postraumática, lesiones de la almohadilla grasa plantar, tenosinovitis de los peroneos y compresión de ramas nerviosas sensitivas. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_98',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué fractura del quinto metatarsiano se trata con yeso en descarga 8 semanas y tiene alta tasa de pseudoartrosis?',opts:['Avulsión de la apófisis estiloides','Fractura de Jones','Fractura por fatiga de la diáfisis proximal en fase aguda','Fractura del cuello del quinto metatarsiano'],ans:1,exp:'<b>Corre :</b> La fractura de Jones (unión metafisodiafisaria del 5.º metatarsiano) se trata con yeso en descarga durante unas 8 semanas y tiene una incidencia relativamente alta de ausencia de consolidación. En deportistas de élite se prefiere la osteosíntesis con tornillo intramedular. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_99',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué exploración complements adicional está indicada para el diagnóstico de la fractura del escafoides cuando la radiografía inicial es negativa?',opts:['TAC urgente','Artroscopia de muñeca','Gammagrafía ósea o RM','Ecografía de partes blandas'],ans:2,exp:'<b>Corre :</b> Cuando la radiografía inicial es negativa y existe sospecha clínica (dolor en tabaquera anatómica), la gammagrafía (hipercaptación) o la RM (cambios precoces) permiten el diagnóstico de la fractura de escafoides. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir1_100',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la diferencia entre osteoinducción y osteoconducción?',opts:['Son sinónimos','Osteoinducción: estimula células propias del receptor para que formen hueso; osteoconducción: proporciona una andamiaje que facilita la invasión ósea sin estimular células','Osteoinducción: solo en autoinjertos; osteoconducción: solo en aloinjertos','Osteoinducción: requiere BMP exógenas; osteoconducción: no'],ans:1,exp:'<b>Corre :</b> Un material es osteoindu r si, añadido a un tejido, estimula sus células para que formen hueso (ej. BMP). Es osteocondu r si facilita su progresiva sustitución por el tejido óseo que lo penetra (ej. aloinjerto, fosfato cálcico). <i>Ref:   Traumatología 10.ª ed.</i>'}
];
